// Every Flutter screen IS a widget tree — nested widgets, parent to child
MaterialApp(
  home: Scaffold(                          // Scaffold is a child of MaterialApp
    appBar: AppBar(
      title: const Text('Home'),           // Text is a leaf — no children
    ),
    body: Column(                          // Column has MANY children
      children: [
        const Padding(
          padding: EdgeInsets.all(16),
          child: Text('Welcome'),
        ),
        Expanded(
          child: ListView.builder(
            itemCount: 100,
            itemBuilder: (context, i) => Card(
              child: ListTile(
                leading: const Icon(Icons.person),
                title: Text('User $i'),
              ),
            ),
          ),
        ),
      ],
    ),
  ),
)
// Depth here: MaterialApp → Scaffold → AppBar → Text
//                                   → Column → Padding → Text
//                                            → Expanded → ListView → Card → ListTile → Icon+Text
// Nothing subclasses anything. It's all COMPOSITION.

import 'package:flutter/material.dart';

void main() => runApp(const MaterialApp(home: HomePage()));

// A composition of small widgets. Extract subtrees into named widgets
// for readability + skip-rebuild wins (Flutter can skip a subtree whose
// widget-config hasn't changed).
class HomePage extends StatelessWidget {
  const HomePage({super.key});

  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('Widget tree demo')),
    body: Column(
      children: const [
        _HeaderCard(title: 'Welcome, Ada'),
        SizedBox(height: 8),
        _StatsRow(users: 42, orders: 137),
        Expanded(child: _UserList()),
      ],
    ),
  );
}

class _HeaderCard extends StatelessWidget {
  const _HeaderCard({required this.title});
  final String title;
  @override
  Widget build(BuildContext context) => Card(
    margin: const EdgeInsets.all(16),
    child: Padding(
      padding: const EdgeInsets.all(16),
      child: Text(title, style: Theme.of(context).textTheme.headlineSmall),
    ),
  );
}

class _StatsRow extends StatelessWidget {
  const _StatsRow({required this.users, required this.orders});
  final int users, orders;
  @override
  Widget build(BuildContext context) => Row(
    mainAxisAlignment: MainAxisAlignment.spaceEvenly,
    children: [
      _Stat(label: 'Users', value: users),
      _Stat(label: 'Orders', value: orders),
    ],
  );
}

class _Stat extends StatelessWidget {
  const _Stat({required this.label, required this.value});
  final String label; final int value;
  @override
  Widget build(BuildContext context) => Column(
    children: [Text('$value', style: const TextStyle(fontSize: 24)), Text(label)],
  );
}

class _UserList extends StatelessWidget {
  const _UserList();
  @override
  Widget build(BuildContext context) => ListView.builder(
    itemCount: 20,
    // Give each item a stable ValueKey — preserves State across reorders/filter.
    itemBuilder: (context, i) => ListTile(
      key: ValueKey('user_$i'),
      leading: const Icon(Icons.person),
      title: Text('User $i'),
    ),
  );
}

// Notice: every subtree is small, named, `const` where possible, and passes
// only the data it needs. That's idiomatic Flutter composition.
